#include <stdio.h>
#include <stdbool.h>
#define MAX_N 100005
bool isUnderAttack(int x, int y, int knights[][2], int n) {
    for (int i = 0; i < n; i++) {
        int dx = abs(x - knights[i][0]);
        int dy = abs(y - knights[i][1]);
        if ((dx == 2 && dy == 1) || (dx == 1 && dy == 2)) {
            return true;
        }
    }
    return false;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        int knights[MAX_N][2];
        for (int i = 0; i < n; i++) {
            scanf("%d %d", &knights[i][0], &knights[i][1]);
        }
        int x, y;
        scanf("%d %d", &x, &y);
        bool isCheckmate = isUnderAttack(x, y, knights, n);
        bool canMove = false;
        for (int dx = -1; dx <= 1; dx++) {
            for (int dy = -1; dy <= 1; dy++) {
                if (dx == 0 && dy == 0) continue;
                if (!isUnderAttack(x + dx, y + dy, knights, n)) {
                    canMove = true;
                    break;
                }
            }
            if (canMove) break;
        }
        if (isCheckmate && !canMove) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

